import React, { useState, useEffect } from 'react';
import { Play, Pause, SkipBack, SkipForward, Shuffle, Repeat, Volume2, Heart, ExternalLink } from 'lucide-react';
import { getGenreStyle } from '../utils/helpers';

export default function Player({ currentTrack, isPlaying, setIsPlaying, onNext, onPrev, toggleLike, isLiked }) {
  const [progress, setProgress] = useState(0);
  const [volume, setVolume] = useState(70);

  useEffect(() => {
    if (!isPlaying) return;
    const interval = setInterval(() => {
      setProgress(p => {
        if (p >= 100) { setIsPlaying(false); return 0; }
        return p + 0.2;
      });
    }, 100);
    return () => clearInterval(interval);
  }, [isPlaying, setIsPlaying]);

  useEffect(() => { setProgress(0); }, [currentTrack]);

  const genre = currentTrack?.genre || 'pop';
  const style = getGenreStyle(genre);
  const duration = Math.floor(180 + Math.random() * 120);
  const elapsed = Math.floor((progress / 100) * duration);
  const fmt = (s) => `${Math.floor(s / 60)}:${(s % 60).toString().padStart(2, '0')}`;

  if (!currentTrack) {
    return (
      <div className="player" style={{ justifyContent: 'center', color: 'var(--text-subdued)' }}>
        <p>Select a track to start listening</p>
      </div>
    );
  }

  return (
    <div className="player">
      {/* Left - Track Info */}
      <div className="player-left">
        <div className="player-art" style={{ '--c1': style.c1, '--c2': style.c2 }}>
          {style.emoji}
        </div>
        <div className="player-info">
          <h4>{currentTrack.title}</h4>
          <p>{currentTrack.artist}</p>
        </div>
        <button
          className={`icon-btn ${isLiked(currentTrack.id) ? 'liked' : ''}`}
          onClick={() => toggleLike(currentTrack)}
        >
          <Heart size={18} fill={isLiked(currentTrack.id) ? 'currentColor' : 'none'} />
        </button>
        {currentTrack.streaming && (
          <a
            href={currentTrack.streaming.spotify}
            target="_blank"
            rel="noreferrer"
            className="icon-btn"
            title="Open on Spotify"
          >
            <ExternalLink size={16} />
          </a>
        )}
      </div>

      {/* Center - Controls */}
      <div className="player-center">
        <div className="player-controls">
          <button className="ctrl-btn"><Shuffle size={18} /></button>
          <button className="ctrl-btn" onClick={onPrev}><SkipBack size={22} /></button>
          <button className="play-btn" onClick={() => setIsPlaying(!isPlaying)}>
            {isPlaying ? <Pause size={18} /> : <Play size={18} />}
          </button>
          <button className="ctrl-btn" onClick={onNext}><SkipForward size={22} /></button>
          <button className="ctrl-btn"><Repeat size={18} /></button>
        </div>
        <div className="progress-bar-wrap">
          <span className="progress-time">{fmt(elapsed)}</span>
          <div className="progress-bar" onClick={(e) => {
            const rect = e.currentTarget.getBoundingClientRect();
            setProgress(((e.clientX - rect.left) / rect.width) * 100);
          }}>
            <div className="progress-fill" style={{ width: `${progress}%` }} />
          </div>
          <span className="progress-time right">{fmt(duration)}</span>
        </div>
      </div>

      {/* Right - Volume */}
      <div className="player-right">
        <button className="ctrl-btn"><Volume2 size={18} /></button>
        <div className="volume-bar" onClick={(e) => {
          const rect = e.currentTarget.getBoundingClientRect();
          setVolume(Math.round(((e.clientX - rect.left) / rect.width) * 100));
        }}>
          <div className="volume-fill" style={{ width: `${volume}%` }} />
        </div>
      </div>
    </div>
  );
}
